prepared_lines as (
  select case
    when coalesce((line->>'is_new')::boolean, false) then
      line || jsonb_build_object(
        'theorique', 0,
        'ecart', coalesce((line->>'physique')::numeric, 0)
      )
    else
      line || jsonb_build_object(
        'theorique', coalesce(
          case
            when trim(coalesce(stock.payload->>'stock', '')) ~ '^-?[0-9]+([.,][0-9]+)?$'
              then replace(stock.payload->>'stock', ',', '.')::numeric
          end,
          0
        ),
        'ecart', coalesce((line->>'physique')::numeric, 0) - coalesce(
          case
            when trim(coalesce(stock.payload->>'stock', '')) ~ '^-?[0-9]+([.,][0-9]+)?$'
              then replace(stock.payload->>'stock', ',', '.')::numeric
          end,
          0
        )
      )
  end as line
  from raw_lines
  left join public.csa_events stock
    on stock.table_name = 'pharma_stock'
   and stock.item_id = raw_lines.line->>'med_id'
),
inventory_payload as (
  select jsonb_build_object(
    'id', 'INV-PHYSIQUE-2026-06-12-V3',
    'reference', 'INV-PHYSIQUE-2026-06-12-V3',
    'date', '2026-06-12',
    'inventory_date', '2026-06-12',
    'source_file', 'Plan_Approvisionnement_CSA_V3.xlsx',
    'source_sheet', '1. Inventaire & Statuts',
    'observation', 'Inventaire physique importe apres correction des rapprochements catalogue. Validation obligatoire du Medecin-Chef.',
    'statut', 'EN_ATTENTE_CHEF',
    'imported_inventory', true,
    'import_summary', jsonb_build_object(
      'source_rows', 69,
      'inventory_lines', 68,
      'existing_products', 39,
      'new_products', 29,
      'review_required', 6,
      'raw_quantity_sum', 21602
    ),
    'lignes', jsonb_agg(line order by (line->>'source_row')::integer),
    'agent_id', 'SYSTEME',
    'agent_nom', 'Import inventaire physique pharmacie V3',
    'created_at', now(),
    'updated_at', now(),
    'synced', true
  ) as payload
  from prepared_lines
)
insert into public.csa_events (
  event_key, table_name, item_id, payload, created_at, updated_at, agent_id, agent_nom
)
select
  'pharma_inventaires:INV-PHYSIQUE-2026-06-12-V3',
  'pharma_inventaires',
  'INV-PHYSIQUE-2026-06-12-V3',
  payload,
  now(),
  now(),
  'SYSTEME',
